import random
import time
import threading

class Lift:
    def __init__(self, id, floors):
        self.id = id
        self.floors = floors
        self.current_floor = 1
        self.passengers = 0
        self.lock = threading.Lock()

    def move(self, target_floor):
        with self.lock:
            if self.current_floor < target_floor:
                for i in range(self.current_floor, target_floor):
                    print(f"Lift {self.id} moving up from floor {i} to {i+1}")
                    time.sleep(0.1)
            elif self.current_floor > target_floor:
                for i in range(self.current_floor, target_floor, -1):
                    print(f"Lift {self.id} moving down from floor {i} to {i-1}")
                    time.sleep(0.1)
            self.current_floor = target_floor

    def pick_up(self, num_passengers):
        with self.lock:
            self.passengers += num_passengers
            print(f"Lift {self.id} picked up {num_passengers} passengers at floor {self.current_floor}")

    def drop_off(self, num_passengers):
        with self.lock:
            self.passengers -= num_passengers
            print(f"Lift {self.id} dropped off {num_passengers} passengers at floor {self.current_floor}")


class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.num_lifts = num_lifts
        self.lifts = [Lift(i, num_floors) for i in range(1, num_lifts+1)]

    def simulate(self, crowd_size, hour):
        if hour < 8 or hour > 17:
            crowd_size = crowd_size // 2
        elif hour < 9 or hour > 16:
            crowd_size = crowd_size * 2
        for _ in range(crowd_size):
            lift = random.choice(self.lifts)
            target_floor = random.randint(1, self.num_floors)
            lift.move(target_floor)
            lift.pick_up(1)
            target_floor = random.randint(1, self.num_floors)
            lift.move(target_floor)
            lift.drop_off(1)


def main():
    num_floors = 20
    num_lifts = 5
    crowd_size = 10
    building = Building(num_floors, num_lifts)
    for hour in range(24):
        print(f"Hour: {hour}")
        building.simulate(crowd_size, hour)
        time.sleep(1)


if __name__ == "__main__":
    main()

