class Lift:
    def __init__(self, id, floors):
        self.id = id
        self.floors = floors
        self.current_floor = 1
        self.queue = []

    def move_to_floor(self, floor):
        if floor != self.current_floor:
            print(f"Lift {self.id} moving from floor {self.current_floor} to floor {floor}")
            self.current_floor = floor
        else:
            print(f"Lift {self.id} is already at floor {self.current_floor}")

    def add_to_queue(self, floor):
        self.queue.append(floor)
        print(f"Lift {self.id} received request to go to floor {floor}")

    def process_queue(self):
        if self.queue:
            floor = self.queue.pop(0)
            self.move_to_floor(floor)
            print(f"Lift {self.id} arrived at floor {floor}")
        else:
            print(f"Lift {self.id} has no requests")

class Building:
    def __init__(self, num_lifts, num_floors):
        self.num_lifts = num_lifts
        self.num_floors = num_floors
        self.lifts = [Lift(i+1, num_floors) for i in range(num_lifts)]

    def simulate(self, crowd_size, hours):
        for hour in range(hours):
            print(f"Hour {hour+1}:")
            if hour < 8 or hour > 17:
                # Night or early morning, fewer requests
                num_requests = random.randint(0, crowd_size // 10)
            elif hour < 9 or hour > 16:
                # Morning or evening rush, more requests
                num_requests = random.randint(crowd_size // 2, crowd_size)
