                # Daytime, moderate requests
                num_requests = random.randint(crowd_size // 5, crowd_size // 2)
            for _ in range(num_requests):
                floor = random.randint(1, self.num_floors)
                lift = random.choice(self.lifts)
                lift.add_to_queue(floor)
            for lift in self.lifts:
                lift.process_queue()
            print()

